import React, { useState, useEffect } from 'react';
import getSubject from '../../api/getSubject.api';
import '../../reusable.css'
import './Subject.css'

function Subject() {
    const [allSubject, setAllSubject] = useState([])
    const [loading, setLoading] = useState(true)
    const [subjectName, setSubjectName] = useState('')

    useEffect(() => {
        getAllSubject()
    }, []);

    // get all unit
    const getAllSubject = async () => {
        await getSubject(setAllSubject, setLoading)
    }

    if (loading) return (<div className='loading-container'><div className='d-flex justify-content-center'><span className="page-loader"></span></div></div>)

    return (
        <div className='subject-container'>
            <div className='new-subject d-flex align-items-center'>
                <span>+</span>
                <p>Add New Subject</p>
            </div>
            <div className='subject-cover d-flex'>
                {allSubject?.map(item => {
                    return (
                        <div key={item._id}>
                            <p>{item.subjectName}</p>
                            <button className='subject-update'>update</button>
                        </div>
                    )
                })}
            </div>
            {/* add subject popup start */}
            <div className="add-subject-popup d-flex justify-content-center align-items-center">
                <div>
                    <p className='text-color'>Add New Subject</p>
                    {(serverOperationError) ? <p className='text-error'>{serverOperationError}</p> : ''}
                    <input type="text" placeholder='Enter the subject name' value={setSubjectName} onChange={e => setSubjectName(e.target.value)} />
                    <button className='button' onClick={update}>{(serverOperationLoading) ? <span className="button-loader"></span> : 'Update'}</button>
                    <button className='button' onClick={closeUpdatePopup}>Cancel</button>
                </div>
            </div>
            {/* add subject popup end */}
        </div>
    )
}

export default Subject
